const items = $input.all()[0].json.vulnerabilities || [];

const extracted = items.map(item => {
  const cve = item.cve.id;

  const cvss =
    item.cve.metrics?.cvssMetricV31?.[0]?.cvssData?.baseScore ||
    item.cve.metrics?.cvssMetricV30?.[0]?.cvssData?.baseScore ||
    5.0;

  const description = (
    item.cve.descriptions?.[0]?.value || 'No description available'
  ).substring(0, 500);

  const epss = Math.random() * 0.7 + 0.1;

  return {
    cve,
    cvss,
    description,
    epss,
    timestamp: new Date().toISOString()
  };
});

return extracted.map(item => ({ json: { item } }));

const item = $json.item;

return [{
  json: {
    item: {
      cve: item.cve,
      cvss: Math.min(Math.max(parseFloat(item.cvss), 0), 10),
      epss: Math.min(Math.max(item.epss, 0), 1),
      description: item.description.trim(),
      normalized_timestamp: new Date().toISOString()
    }
  }
}];

const item = $json.item;

const searchText = item.description.toLowerCase();

let asset = 'Sistema General';
let criticality = 5;

if (searchText.includes('nginx')) {
  asset = 'Servidor Nginx';
  criticality = 10;
}

if (searchText.includes('apache')) {
  asset = 'Servidor Apache';
  criticality = 8;
}

if (searchText.includes('wordpress')) {
  asset = 'Aplicación WordPress';
  criticality = 6;
}

if (searchText.includes('tomcat')) {
  asset = 'Servidor Tomcat';
  criticality = 8;
}

return [{
  json: {
    item: {
      ...item,
      correlated_asset: asset,
      asset_criticality: criticality
    }
  }
}];

const item = $json.item;

const irc =
  (item.cvss * 0.4) +
  (item.epss * 0.4) +
  (item.asset_criticality * 0.2);

return [{
  json: {
    item: {
      ...item,
      irc: parseFloat(irc.toFixed(2))
    }
  }
}];

const item = $json.item;

return [{
  json: {
    item: {
      ...item,
      is_critical: true,
      severity_override: 'Crítica',
      alert_event: 'CRITICAL_ALERT_GENERATED'
    }
  }
}];

const item = $json.item;

let severity = 'Baja';

if (item.irc >= 5.0) {
  severity = 'Alta';
} else if (item.irc >= 2.5) {
  severity = 'Media';
}

return [{
  json: {
    item: {
      ...item,
      is_critical: false,
      severity_override: severity,
      alert_event: null
    }
  }
}];

const item = $json.item;

const severity = item.severity_override;

let analyst_id = 2;

if (severity === 'Crítica') {
  analyst_id = Math.random() > 0.5 ? 2 : 3;
} else if (severity === 'Alta') {
  analyst_id = 2;
} else if (severity === 'Media') {
  analyst_id = 2;
} else {
  analyst_id = 3;
}

const companyIds = [1, 2, 3];
const randomCompanyId = companyIds[Math.floor(Math.random() * companyIds.length)];

return [{
  json: {
    payload: {
      cve: item.cve,
      description: item.description,
      irc: item.irc,
      severity: severity,
      status: 'Pendiente',
      company_id: randomCompanyId,
      assigned_analyst_id: analyst_id,
      metadata: {
        correlated_asset: item.correlated_asset,
        asset_criticality: item.asset_criticality,
        cvss: item.cvss,
        epss: item.epss,
        is_critical: item.is_critical,
        alert_event: item.alert_event,
        processed_at: new Date().toISOString()
      }
    }
  }
}];

const allResults = $input.all();

let successCount = 0;
let errorCount = 0;

allResults.forEach(result => {
  if (result.json) {
    successCount++;
  } else {
    errorCount++;
  }
});

return [{
  json: {
    execution_summary: {
      timestamp: new Date().toISOString(),
      total_processed: successCount + errorCount,
      success_count: successCount,
      error_count: errorCount,
      status: errorCount === 0 ? 'SUCCESS' : 'PARTIAL_SUCCESS'
    }
  }
}];
